$token = $env:GITHUB_TOKEN; if (-not $token) { $token = git config --get user.token }; if (-not $token) { Write-Error "ERROR: GITHUB_TOKEN not set"; exit 1 }; $cid = $null; try { $json = gh api graphql -f query='query{repository(owner:"riskiipriyadi",name:"sinibaca"){discussionCategories(first:10){nodes{id name}}}}' 2>$null; if ($json) { $data = $json | ConvertFrom-Json; $nodes = $data.data.repository.discussionCategories.nodes; $general = $nodes | Where-Object { $_.name -eq 'General' }; if ($general) { $cid = $general.id } } } catch {}; if (-not $cid) { try { $response = curl -s -H "Authorization: Bearer $token" -H "Accept: application/vnd.github+json" -H "X-GitHub-Api-Version: 2022-11-28" "https://api.github.com/repos/riskiipriyadi/sinibaca/discussions/categories" 2>$null; if ($response) { $data = $response | ConvertFrom-Json; $general = $data | Where-Object { $_.name -eq 'General' }; if ($general) { $cid = $general.node_id } } } catch {}; }; if (-not $cid) { try { $response = curl -s "https://api.github.com/repos/riskiipriyadi/sinibaca/discussions/categories" 2>$null; if ($response) { $data = $response | ConvertFrom-Json; $general = $data | Where-Object { $_.name -eq 'General' }; if ($general) { $cid = $general.node_id } } } catch {}; }; if (-not $cid) { Write-Error "ERROR: Cannot fetch category ID. Run 'gh auth login' or export GITHUB_TOKEN=ghp_xxx"; exit 1 }; (Get-Content _config.yml) -replace 'category_id: <CATEGORY_ID>', "category_id: $cid" | Set-Content _config.yml; if (Select-String -Pattern "category_id: $cid" _config.yml -Quiet) { git add -A; git commit -m "Configure valid Giscus category ID"; git push } else { Write-Error "Failed to update _config.yml"; exit 1 }